		// 	// When wheather forecast cannot be downloaded we get NULL
		// 	if( ! (forecastJson=="<code>NULL</code>")) {

		// 		// Extract only section about rainfall, looked at
		// 		// https://community.openhab.org/t/solved-smhi-weather/22300/20
