		//   	    var String[] rainValues  = transform("JSONPATH","$.list[*].rain.3h", forecastJson).replace("[", "").replace("]", "").split(",") 
	  	// 		rainfallMm = 0

		// 		// Check if there is at least one 'rain' section i json
